class Solution {
public:
    int minChanges(int n, int k) {
        int changes = 0;
        while (n != k && n > 0) {
            if ((n & k) != k) return -1;
            changes++;
            n = n ^ (n & -n);
        }
        return n == k ? changes : -1;
    }
};

